let owning_c = pre_self_.get_thread(thread_ptr).owning_container;

// ---- Domain bridges (cheap; force `=~=` on the four perms-dom maps so they
// share a single canonical dom in the SMT proof) ----
assert(post1_self_.proc_dom() == post2_self_.proc_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom());
assert(post1_self_.endpoint_perms@.dom() =~= post2_self_.endpoint_perms@.dom());

// ---- Bridge get_proc across the two runs ----
// The two ensures use disjoint triggers (post1.get_proc(p) vs post2.get_proc(p)).
// Force a unified instantiation with explicit dual triggers.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger post2_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post2_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
};

// ---- Bridge get_container across the two runs, at unchanged containers ----
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr) && c_ptr != owning_c
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post2_self_.container_dom().contains(c_ptr));
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
};

// ---- Bridge get_thread across the two runs, at unchanged threads ----
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
};

// ---- Bridge get_endpoint across the two runs, at unchanged endpoints ----
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
    assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
};

// ---- Pin the modified container at owning_c (every field ensures fixes) ----
assert(post1_self_.get_container(owning_c).owned_cpus
    == post2_self_.get_container(owning_c).owned_cpus);
assert(post1_self_.get_container(owning_c).owned_threads
    == post2_self_.get_container(owning_c).owned_threads);
assert(post1_self_.get_container(owning_c).scheduler
    == post2_self_.get_container(owning_c).scheduler);
assert(post1_self_.get_container(owning_c).owned_endpoints@
    =~= pre_self_.get_container(owning_c).owned_endpoints@.insert(page_ptr_1));
assert(post2_self_.get_container(owning_c).owned_endpoints@
    =~= pre_self_.get_container(owning_c).owned_endpoints@.insert(page_ptr_1));
assert(post1_self_.get_container(owning_c).owned_endpoints@
    =~= post2_self_.get_container(owning_c).owned_endpoints@);
assert(post1_self_.get_container(owning_c).children
    == post2_self_.get_container(owning_c).children);

// ---- Pin the modified thread at thread_ptr (every field ensures fixes) ----
assert(post1_self_.get_thread(thread_ptr).ipc_payload
    =~= pre_self_.get_thread(thread_ptr).ipc_payload);
assert(post2_self_.get_thread(thread_ptr).ipc_payload
    =~= pre_self_.get_thread(thread_ptr).ipc_payload);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
    =~= post2_self_.get_thread(thread_ptr).ipc_payload);
assert(post1_self_.get_thread(thread_ptr).state
    =~= pre_self_.get_thread(thread_ptr).state);
assert(post2_self_.get_thread(thread_ptr).state
    =~= pre_self_.get_thread(thread_ptr).state);
assert(post1_self_.get_thread(thread_ptr).state
    =~= post2_self_.get_thread(thread_ptr).state);
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(endpoint_index as int, Some(page_ptr_1)));
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(endpoint_index as int, Some(page_ptr_1)));
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors@);

// ---- Pin the newly-created endpoint at page_ptr_1 ----
assert(post1_self_.get_endpoint(page_ptr_1).queue@ =~= Seq::<ThreadPtr>::empty());
assert(post2_self_.get_endpoint(page_ptr_1).queue@ =~= Seq::<ThreadPtr>::empty());
assert(post1_self_.get_endpoint(page_ptr_1).queue@
    =~= post2_self_.get_endpoint(page_ptr_1).queue@);
assert(post1_self_.get_endpoint(page_ptr_1).queue_state =~= EndpointState::SEND);
assert(post2_self_.get_endpoint(page_ptr_1).queue_state =~= EndpointState::SEND);
assert(post1_self_.get_endpoint(page_ptr_1).queue_state
    =~= post2_self_.get_endpoint(page_ptr_1).queue_state);
assert(post1_self_.get_endpoint(page_ptr_1).rf_counter =~= 1);
assert(post2_self_.get_endpoint(page_ptr_1).rf_counter =~= 1);
assert(post1_self_.get_endpoint(page_ptr_1).rf_counter
    =~= post2_self_.get_endpoint(page_ptr_1).rf_counter);
assert(post1_self_.get_endpoint(page_ptr_1).owning_threads@
    =~= Set::<(ThreadPtr, EndpointIdx)>::empty().insert((thread_ptr, endpoint_index)));
assert(post2_self_.get_endpoint(page_ptr_1).owning_threads@
    =~= Set::<(ThreadPtr, EndpointIdx)>::empty().insert((thread_ptr, endpoint_index)));
assert(post1_self_.get_endpoint(page_ptr_1).owning_threads@
    =~= post2_self_.get_endpoint(page_ptr_1).owning_threads@);
assert(post1_self_.get_endpoint(page_ptr_1).owning_container =~= owning_c);
assert(post2_self_.get_endpoint(page_ptr_1).owning_container =~= owning_c);
assert(post1_self_.get_endpoint(page_ptr_1).owning_container
    =~= post2_self_.get_endpoint(page_ptr_1).owning_container);
